function saveDriveClientId(){
  const val=document.getElementById('drive-client-id').value.trim();
  if(!val){alert('Please paste your Client ID first.');return;}
  if(!val.includes('.apps.googleusercontent.com')){alert("That doesn't look like a valid Client ID.");return;}
  localStorage.setItem('vida_drive_client_id',val);
  _setDriveStatus('ready','Client ID saved — click Connect to Google to authorise.');
}
function restoreDriveSettings(){
  const id=localStorage.getItem('vida_drive_client_id');
  const email=localStorage.getItem('vida_drive_email');
  if(id){const el=document.getElementById('drive-client-id');if(el)el.value=id;}
  if(email){const el=document.getElementById('drive-account');if(el)el.value=email;_setDriveStatus('ready','Previously connected as '+email+'. Click Connect to restore.');}
}
function _setDriveStatus(type,msg){
  const bar=document.getElementById('drive-status-bar');
  const txt=document.getElementById('drive-status-text');
  if(!bar||!txt)return;
  const s={disconnected:'background:var(--color-background-warning);color:var(--color-text-warning);border:.5px solid var(--color-border-warning)',ready:'background:var(--color-background-info);color:var(--color-text-info);border:.5px solid var(--color-border-info)',connected:'background:var(--color-background-success);color:var(--color-text-success);border:.5px solid var(--color-border-success)',error:'background:var(--color-background-danger);color:var(--color-text-danger);border:.5px solid var(--color-border-danger)'};
  bar.style.cssText=(s[type]||s.disconnected)+';display:flex;align-items:center;gap:8px;padding:10px 14px;border-radius:var(--border-radius-md);font-size:13px;margin-bottom:1rem';
  txt.textContent=msg;
}

function calcOrder(o){
  const ship=o.isActualized&&o.actShip!=null?o.actShip:o.estShip;
  const clear=o.isActualized&&o.actClear!=null?o.actClear:o.estClear;
  const extras=(o.isActualized?o.actExtra:o.estExtra)||[];
  const extraTotal=extras.reduce((a,e)=>a+(+e.amt||0),0);
  let totalQty=0;
  o.items.forEach(it=>{it._rawQty=it.sizes.reduce((a,v)=>a+(+v||0),0);it._effQty=Math.max(it._rawQty+(+it.adj||0),1);totalQty+=it._effQty;});
  let rRev=0,wRev=0,cRev=0,tLanded=0;
  o.items.forEach(it=>{
    const sU=totalQty>0?ship/totalQty:0,clU=totalQty>0?clear/totalQty:0,exU=totalQty>0?extraTotal/totalQty:0;
    it._landedU=it.unitPrice+sU+clU+exU;it._retail=it._landedU*(1+(+it.markup||0)/100);it._tLanded=it._landedU*it._effQty;tLanded+=it._tLanded;
    it.channels.forEach(ch=>{
      if(ch.type==='retail'){ch.price=it._retail;rRev+=ch.price*(+ch.qty||0);}
      else if(ch.type==='wholesale'){ch.price=ch.wsType==='fixed'?(+ch.wsFixed||0):it._retail*(1-(+ch.wsPct||0)/100);wRev+=ch.price*(+ch.qty||0);}
      else{cRev+=(+ch.price||0)*(+ch.qty||0);}
    });
  });
  const tRev=rRev+wRev+cRev,margin=tRev>0?(tRev-tLanded)/tRev*100:0,units=o.items.reduce((a,it)=>a+it._effQty,0);
  return{ship,clear,extraTotal,tLanded,rRev,wRev,cRev,tRev,margin,units};
}
function calcCustomer(cust){
  const ords=orders.filter(o=>cust.orderIds.includes(o.id));
  const calcs=ords.map(o=>calcOrder(o));
  const wsRev=calcs.reduce((a,c)=>a+c.wRev,0),custRev=calcs.reduce((a,c)=>a+c.cRev,0),tRev=wsRev+custRev;
  const tLanded=calcs.reduce((a,c)=>a+(tRev>0?(c.wRev+c.cRev)/c.tRev*c.tLanded:0),0);
  const margin=tRev>0?(tRev-tLanded)/tRev*100:0,units=calcs.reduce((a,c)=>a+c.units,0);
  const productCount=ords.reduce((a,o)=>a+o.items.filter(it=>it.channels.some(ch=>ch.type!=='retail')).length,0);
  const orderCount=ords.length,avgOrder=orderCount>0?tRev/orderCount:0;
  const colls=collections.filter(c=>cust.collectionIds.includes(c.id));
  return{wsRev,custRev,tRev,margin,units,productCount,orderCount,avgOrder,tLanded,colls,ords,calcs};
}
function getCollPL(c){
  const ords=orders.filter(o=>c.orderIds.includes(o.id)),calcs=ords.map(o=>calcOrder(o));
  const tLanded=calcs.reduce((a,x)=>a+x.tLanded,0),rRev=calcs.reduce((a,x)=>a+x.rRev,0),wRev=calcs.reduce((a,x)=>a+x.wRev,0),cRev=calcs.reduce((a,x)=>a+x.cRev,0);
  const tRev=rRev+wRev+cRev,margin=tRev>0?(tRev-tLanded)/tRev*100:0,units=calcs.reduce((a,x)=>a+x.units,0);
  const sizes=SIZES.map((_,i)=>ords.reduce((a,o)=>a+o.items.reduce((b,it)=>b+(+it.sizes[i]||0),0),0));
  return{orders:ords.length,units,tLanded,rRev,wRev,cRev,tRev,margin,sizes,ords,calcs};
}
function custTier(ltv){return ltv>10000?'Gold':ltv>3000?'Silver':'New';}
function tierBadge(ltv){const t=custTier(ltv);return`<span class="tier-badge tier-${t.toLowerCase()}">${t}</span>`;}

