function showSupTab(id,el){['sup-tab-info','sup-tab-products'].forEach(t=>{const e=document.getElementById(t);if(e)e.style.display='none';});document.querySelectorAll('#sup-modal-tabs .tab').forEach(t=>t.classList.remove('active'));document.getElementById(id).style.display='block';el.classList.add('active');}

function populateSupProdAddSelect(){
  const sel=document.getElementById('sup-prod-add-select');
  const assigned=_supProdDraft.map(x=>x.productId);
  const available=allProducts().filter(p=>!assigned.includes(p.id));
  const byGroup={};available.forEach(p=>{const k=p.groupId||'';if(!byGroup[k])byGroup[k]=[];byGroup[k].push(p);});
  sel.innerHTML='<option value="">Select product to add...</option>';
  productGroups.forEach(g=>{if(!byGroup[g.id]||!byGroup[g.id].length)return;const og=document.createElement('optgroup');og.label=g.name;byGroup[g.id].forEach(p=>{const o=document.createElement('option');o.value=p.id;o.textContent=p.name;og.appendChild(o);});sel.appendChild(og);});
  if(byGroup['']&&byGroup[''].length){const og=document.createElement('optgroup');og.label='Other';byGroup[''].forEach(p=>{const o=document.createElement('option');o.value=p.id;o.textContent=p.name;og.appendChild(o);});sel.appendChild(og);}
}

function renderSupProdList(){
  const el=document.getElementById('sup-prod-list');
  if(!_supProdDraft.length){el.innerHTML='<div style="font-size:12px;color:var(--color-text-secondary);font-style:italic;padding:8px 0">No products assigned yet.</div>';populateSupProdAddSelect();return;}
  const byGroup={};
  _supProdDraft.forEach(sp=>{const p=allProducts().find(x=>x.id===sp.productId);if(!p)return;const k=p.groupId||'';if(!byGroup[k])byGroup[k]=[];byGroup[k].push({sp,p});});
  let html='';
  productGroups.forEach(g=>{
    if(!byGroup[g.id]||!byGroup[g.id].length)return;
    html+=`<div style="font-size:11px;color:var(--color-text-secondary);text-transform:uppercase;letter-spacing:.04em;padding:10px 0 4px;font-weight:500">${g.name}</div>`;
    byGroup[g.id].forEach(({sp,p})=>{html+=`<div class="sup-prod-row"><span style="flex:1;font-size:13px">${p.name}</span><input type="number" value="${sp.cost}" min="0" step="0.01" data-pid="${sp.productId}" onchange="updateSupProdCost(this)" style="width:110px;text-align:right;font-family:var(--font-mono);font-size:13px"><span style="font-size:11px;color:var(--color-text-secondary);min-width:40px">/ unit</span><button class="btn btnsm btndanger" onclick="removeSupProd('${sp.productId}')" style="padding:3px 8px;font-size:11px">×</button></div>`;});
  });
  if(byGroup['']&&byGroup[''].length){html+=`<div style="font-size:11px;color:var(--color-text-secondary);text-transform:uppercase;letter-spacing:.04em;padding:10px 0 4px;font-weight:500">Other</div>`;byGroup[''].forEach(({sp,p})=>{html+=`<div class="sup-prod-row"><span style="flex:1;font-size:13px">${p.name}</span><input type="number" value="${sp.cost}" min="0" step="0.01" data-pid="${sp.productId}" onchange="updateSupProdCost(this)" style="width:110px;text-align:right;font-family:var(--font-mono);font-size:13px"><span style="font-size:11px;color:var(--color-text-secondary);min-width:40px">/ unit</span><button class="btn btnsm btndanger" onclick="removeSupProd('${sp.productId}')" style="padding:3px 8px;font-size:11px">×</button></div>`;});}
  el.innerHTML=html;
  populateSupProdAddSelect();
}
function addSupplierProduct(){const sel=document.getElementById('sup-prod-add-select');const cost=parseFloat(document.getElementById('sup-prod-add-cost').value)||0;if(!sel.value){alert('Select a product first.');return;}if(_supProdDraft.find(x=>x.productId===sel.value)){alert('Already added.');return;}_supProdDraft.push({productId:sel.value,cost});document.getElementById('sup-prod-add-cost').value='0';renderSupProdList();}
function updateSupProdCost(inp){const sp=_supProdDraft.find(x=>x.productId===inp.dataset.pid);if(sp)sp.cost=parseFloat(inp.value)||0;}
function removeSupProd(productId){const i=_supProdDraft.findIndex(x=>x.productId===productId);if(i>-1)_supProdDraft.splice(i,1);renderSupProdList();}

