function onSupChange(){
  const supId=document.getElementById('no-sup').value;
  const sup=suppliers.find(x=>x.id===supId);
  if(sup)document.getElementById('no-cur').value=sup.currency||'USD';
  document.querySelectorAll('#items-wrap .card').forEach(card=>{const sel=card.querySelector('.iptype');if(sel)refreshItemProductSelect(sel,supId);});
}

function refreshItemProductSelect(sel,supId){
  const currentVal=sel.value;
  sel.innerHTML='<option value="">Select product...</option>';
  if(!supId){
    const og1=document.createElement('optgroup');og1.label='Core products';coreProducts.forEach(p=>{const o=document.createElement('option');o.value=p.id;o.textContent=p.name;og1.appendChild(o);});
    const og2=document.createElement('optgroup');og2.label='Custom products';customProducts.forEach(p=>{const o=document.createElement('option');o.value=p.id;o.textContent=p.name;og2.appendChild(o);});
    sel.appendChild(og1);sel.appendChild(og2);
  } else {
    const supProds=getSupplierProducts(supId);
    if(!supProds.length){const o=document.createElement('option');o.disabled=true;o.textContent='No products assigned to this supplier yet';sel.appendChild(o);}
    else{
      const byGroup={};supProds.forEach(sp=>{const p=allProducts().find(x=>x.id===sp.productId);if(!p)return;const k=p.groupId||'';if(!byGroup[k])byGroup[k]=[];byGroup[k].push({p,sp});});
      productGroups.forEach(g=>{if(!byGroup[g.id]||!byGroup[g.id].length)return;const og=document.createElement('optgroup');og.label=g.name;byGroup[g.id].forEach(({p,sp})=>{const o=document.createElement('option');o.value=p.id;o.textContent=p.name+' — $'+sp.cost.toFixed(2);og.appendChild(o);});sel.appendChild(og);});
      if(byGroup['']&&byGroup[''].length){const og=document.createElement('optgroup');og.label='Other';byGroup[''].forEach(({p,sp})=>{const o=document.createElement('option');o.value=p.id;o.textContent=p.name+' — $'+sp.cost.toFixed(2);og.appendChild(o);});sel.appendChild(og);}
    }
  }
  if(currentVal&&[...sel.options].some(o=>o.value===currentVal))sel.value=currentVal;
}

function onItemProductChange(sel){
  const card=sel.closest('.card');const supId=document.getElementById('no-sup').value;
  if(!supId||!sel.value)return;
  const cost=getSupplierProductCost(supId,sel.value);
  if(cost!==null){
    const upInput=card.querySelector('.up');if(!upInput)return;
    upInput.value=cost.toFixed(2);
    let badge=card.querySelector('.autofill-badge');
    if(!badge){badge=document.createElement('span');badge.className='autofill-badge';upInput.parentElement.appendChild(badge);}
    badge.textContent='Auto-filled';setTimeout(()=>{if(badge)badge.textContent='';},2500);
    recalc();
  }
}

function addItem(){
  itemIdx++;const id='itm'+itemIdx;const supId=document.getElementById('no-sup').value;
  const div=document.createElement('div');div.className='card';div.id=id;
  div.innerHTML=`<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><div style="font-weight:500">Item ${itemIdx}</div><button class="btn btnsm" onclick="document.getElementById('${id}').remove();recalc()">Remove</button></div>
  <div class="row" style="margin-bottom:10px">
    <div style="flex:2"><label>Item name / description</label><input class="iname" placeholder="e.g. Tropical Floral Tee" oninput="recalc()"></div>
    <div style="flex:2"><label>Product type</label><select class="iptype" onchange="onItemProductChange(this);recalc()"><option value="">Select product...</option></select></div>
    <div><label>Unit price ($)</label><input type="number" value="0" min="0" step="0.01" class="up" oninput="recalc()"></div>
    <div><label>Markup %</label><select class="mu" onchange="recalc()">${markups.map(m=>`<option value="${m}" ${m===100?'selected':''}>${m}%</option>`).join('')}</select></div>
    <div><label>Qty adj</label><input type="number" value="0" class="adj" oninput="recalc()"></div>
  </div>
  <div class="row" style="margin-bottom:10px">
    <div style="flex:2"><label>Design(s)</label><div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center"><select class="idesign-sel" style="flex:1;min-width:160px" onchange="addDesignTag(this)"><option value="">Add design...</option>${designs.map(d=>`<option value="${d.id}">${d.name}${d.cat?' ('+d.cat+')':''}</option>`).join('')}</select><div class="idesign-tags" style="display:flex;flex-wrap:wrap;gap:4px"></div></div></div>
    <div style="flex:2"><label>Colorway(s)</label><div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center"><select class="icolor-sel" style="flex:1;min-width:140px" onchange="addColorTag(this)"><option value="">Add color...</option>${colors.map(c=>`<option value="${c.id}">${c.name}</option>`).join('')}</select><div class="icolor-tags" style="display:flex;flex-wrap:wrap;gap:4px"></div></div></div>
  </div>
  <div style="font-size:12px;color:var(--color-text-secondary);margin-bottom:4px">Quantity by size</div>
  <div class="szlabels">${SIZES.map(s=>`<span>${s}</span>`).join('')}</div>
  <div class="szgrid">${SIZES.map(()=>`<input type="number" value="0" min="0" class="sq" oninput="recalc()">`).join('')}</div>
  <div class="divider"></div>
  <div style="font-size:12px;font-weight:500;color:var(--color-text-secondary);margin-bottom:8px;text-transform:uppercase">Sales channels</div>
  <div class="channels-wrap"></div>
  <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:8px">
    <button class="btn btnsm bretail" onclick="addChan(this,'retail')">+ Retail</button>
    <button class="btn btnsm bwholesale" onclick="addChan(this,'wholesale')">+ Wholesale</button>
    <button class="btn btnsm bcustom" onclick="addChan(this,'custom')">+ Custom order</button>
  </div>
  <div style="display:flex;flex-wrap:wrap;gap:10px;margin-top:10px;font-size:12px;color:var(--color-text-secondary)">
    <span>Qty: <strong class="iq">0</strong></span><span>Landed/u: <strong class="il">$0.00</strong></span><span>Retail: <strong class="ir">$0.00</strong></span>
    <span>Retail rev: <strong class="irr" style="color:#378ADD">$0</strong></span><span>WS rev: <strong class="iwr" style="color:#639922">$0</strong></span><span>Custom rev: <strong class="icr" style="color:#BA7517">$0</strong></span><span>Margin: <strong class="im">0%</strong></span>
  </div>`;
  document.getElementById('items-wrap').appendChild(div);
  refreshItemProductSelect(div.querySelector('.iptype'),supId);
  addChan(div.querySelector('.bretail'),'retail');
}

function addDesignTag(sel){if(!sel.value)return;const wrap=sel.parentElement.querySelector('.idesign-tags');if(wrap.querySelector(`[data-id="${sel.value}"]`)){sel.value='';return;}const tag=document.createElement('span');tag.className='colorway-tag';tag.dataset.id=sel.value;tag.innerHTML=`${designName(sel.value)} <span class="xc" onclick="this.parentElement.remove()">×</span>`;wrap.appendChild(tag);sel.value='';}
function addColorTag(sel){if(!sel.value)return;const wrap=sel.parentElement.querySelector('.icolor-tags');if(wrap.querySelector(`[data-id="${sel.value}"]`)){sel.value='';return;}const tag=document.createElement('span');tag.className='colorway-tag';tag.dataset.id=sel.value;tag.style.background='#E1F5EE';tag.style.color='#085041';tag.innerHTML=`${colorName(sel.value)} <span class="xc" onclick="this.parentElement.remove()">×</span>`;wrap.appendChild(tag);sel.value='';}
function addChan(btn,type){const card=btn.closest('.card'),wrap=card.querySelector('.channels-wrap');const ch=document.createElement('div');ch.className='channel-block';const lbl={retail:'Retail',wholesale:'Wholesale',custom:'Custom order'}[type];const bc={retail:'bretail',wholesale:'bwholesale',custom:'bcustom'}[type];let inner=`<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;flex-wrap:wrap"><span class="badge ${bc}">${lbl}</span><div style="flex:1;min-width:80px"><label>Qty</label><input type="number" value="0" min="0" class="ch-qty" data-type="${type}" oninput="recalc()"></div>`;if(type==='wholesale'){inner+=`<div style="min-width:110px"><label>Discount type</label><select class="ch-wstype" onchange="toggleWs(this);recalc()"><option value="pct">% off retail</option><option value="fixed">Fixed price</option></select></div><div class="ch-pct-wrap" style="min-width:80px"><label>Discount %</label><input type="number" value="40" min="0" max="100" class="ch-wspct" oninput="recalc()"></div><div class="ch-fix-wrap" style="min-width:80px;display:none"><label>Fixed price ($)</label><input type="number" value="0" min="0" step="0.01" class="ch-wsfix" oninput="recalc()"></div>`;}else if(type==='custom'){inner+=`<div style="min-width:90px"><label>Custom price ($)</label><input type="number" value="0" min="0" step="0.01" class="ch-custprice" oninput="recalc()"></div><div style="flex:2;min-width:120px"><label>Note</label><input placeholder="e.g. Corp embroidery" class="ch-custnote"></div>`;}inner+=`<button class="btn btnsm" style="margin-left:auto" onclick="this.closest('.channel-block').remove();recalc()">×</button></div>`;ch.innerHTML=inner;wrap.appendChild(ch);recalc();}
function toggleWs(sel){const b=sel.closest('.channel-block');b.querySelector('.ch-pct-wrap').style.display=sel.value==='pct'?'':'none';b.querySelector('.ch-fix-wrap').style.display=sel.value==='fixed'?'':'none';}
function recalc(){const ship=parseFloat(document.getElementById('no-ship').value)||0,clear=parseFloat(document.getElementById('no-clear').value)||0,extra=parseFloat(document.getElementById('no-xamt').value)||0;const cards=[...document.querySelectorAll('#items-wrap .card')];let tQ=0;const qArr=cards.map(card=>{const szs=card.querySelectorAll('.sq');const adj=parseInt(card.querySelector('.adj').value)||0;let q=0;szs.forEach(i=>q+=parseInt(i.value)||0);const eff=Math.max(q+adj,1);tQ+=eff;return{raw:q,eff};});let gL=0,gR=0,gW=0,gC=0;const szT=new Array(9).fill(0);cards.forEach((card,ci)=>{const up=parseFloat(card.querySelector('.up').value)||0,mu=parseFloat(card.querySelector('.mu').value)||0,{eff}=qArr[ci];card.querySelectorAll('.sq').forEach((inp,i)=>szT[i]+=(parseInt(inp.value)||0));const lU=up+(tQ>0?ship/tQ:0)+(tQ>0?clear/tQ:0)+(tQ>0?extra/tQ:0);const retail=lU*(1+mu/100),tL=lU*eff;let rR=0,wR=0,cR=0;card.querySelectorAll('.ch-qty').forEach(inp=>{const type=inp.dataset.type,qty=parseInt(inp.value)||0,block=inp.closest('.channel-block');if(type==='retail'){rR+=retail*qty;}else if(type==='wholesale'){const wst=block.querySelector('.ch-wstype').value;wR+=(wst==='fixed'?parseFloat(block.querySelector('.ch-wsfix').value)||0:retail*(1-(parseFloat(block.querySelector('.ch-wspct').value)||0)/100))*qty;}else{cR+=(parseFloat(block.querySelector('.ch-custprice').value)||0)*qty;}});const tR=rR+wR+cR,m=tR>0?(tR-tL)/tR*100:0;gL+=tL;gR+=rR;gW+=wR;gC+=cR;card.querySelector('.iq').textContent=eff;card.querySelector('.il').textContent='$'+lU.toFixed(2);card.querySelector('.ir').textContent='$'+retail.toFixed(2);card.querySelector('.irr').textContent=f0(rR);card.querySelector('.iwr').textContent=f0(wR);card.querySelector('.icr').textContent=f0(cR);card.querySelector('.im').textContent=fp(m);});szT.forEach((v,i)=>{const el=document.getElementById('st'+i);if(el)el.textContent=v;});const gRev=gR+gW+gC,gm=gRev>0?(gRev-gL)/gRev*100:0;document.getElementById('ord-sum-met').innerHTML=`<div class="metric"><div class="lbl">Units</div><div class="val">${tQ}</div></div><div class="metric"><div class="lbl">Landed cost</div><div class="val">${f0(gL)}</div></div><div class="metric"><div class="lbl">Retail rev</div><div class="val" style="color:#378ADD">${f0(gR)}</div></div><div class="metric"><div class="lbl">WS rev</div><div class="val" style="color:#639922">${f0(gW)}</div></div><div class="metric"><div class="lbl">Margin</div><div class="val" style="color:${gm>50?'#639922':gm>30?'#BA7517':'#E24B4A'}">${fp(gm)}</div></div>`;}
function saveOrder(){const sup=document.getElementById('no-sup').value;if(!sup){alert('Select a supplier.');return;}const num=document.getElementById('no-num').value.trim()||'ORD-'+Date.now();const cards=[...document.querySelectorAll('#items-wrap .card')];const ship=parseFloat(document.getElementById('no-ship').value)||0,clear=parseFloat(document.getElementById('no-clear').value)||0;const xl=document.getElementById('no-xlbl').value.trim(),xa=parseFloat(document.getElementById('no-xamt').value)||0;const estExtra=xl&&xa>0?[{label:xl,amt:xa}]:[];const items=cards.map(card=>{const szs=card.querySelectorAll('.sq'),sizes=[],channels=[];szs.forEach(i=>sizes.push(parseInt(i.value)||0));const adj=parseInt(card.querySelector('.adj').value)||0;const dTags=[...card.querySelectorAll('.idesign-tags [data-id]')].map(t=>t.dataset.id);const cTags=[...card.querySelectorAll('.icolor-tags [data-id]')].map(t=>t.dataset.id);card.querySelectorAll('.ch-qty').forEach(inp=>{const type=inp.dataset.type,qty=parseInt(inp.value)||0;if(!qty)return;const block=inp.closest('.channel-block');if(type==='retail'){channels.push({type,qty,price:0});}else if(type==='wholesale'){const wsType=block.querySelector('.ch-wstype').value;channels.push({type,qty,wsType,wsPct:parseFloat(block.querySelector('.ch-wspct').value)||0,wsFixed:parseFloat(block.querySelector('.ch-wsfix').value)||0,price:0});}else{channels.push({type,qty,price:parseFloat(block.querySelector('.ch-custprice').value)||0,customNote:block.querySelector('.ch-custnote').value});}});return{name:card.querySelector('.iname').value||'Item',productId:card.querySelector('.iptype').value||'',designs:dTags,colorways:cTags,unitPrice:parseFloat(card.querySelector('.up').value)||0,markup:parseFloat(card.querySelector('.mu').value)||0,sizes,adj,channels};});const collId=document.getElementById('no-coll').value||null;orders.push({id:num,supplier:sup,collectionId:collId,date:document.getElementById('no-date').value||new Date().toISOString().slice(0,10),status:'Active',tracking:document.getElementById('no-track').value,carrier:document.getElementById('no-carrier').value,estShip:ship,estClear:clear,estExtra,actShip:null,actClear:null,actExtra:[],isActualized:false,items,steps:[{l:'Order placed',d:true},{l:'Shipped',d:false},{l:'In transit',d:false},{l:'Customs cleared',d:false},{l:'Delivered',d:false}],eta:''});if(collId){const c=collections.find(x=>x.id===collId);if(c&&!c.orderIds.includes(num))c.orderIds.push(num);}document.getElementById('items-wrap').innerHTML='';itemIdx=0;gotoPage('dashboard');}

function renderDashboard(){const allC=orders.map(o=>({o,c:calcOrder(o)}));const tLanded=allC.reduce((a,x)=>a+x.c.tLanded,0),tRev=allC.reduce((a,x)=>a+x.c.tRev,0),tRetail=allC.reduce((a,x)=>a+x.c.rRev,0),tWS=allC.reduce((a,x)=>a+x.c.wRev,0),tCust=allC.reduce((a,x)=>a+x.c.cRev,0),avgM=tRev>0?(tRev-tLanded)/tRev*100:0;document.getElementById('dmets').innerHTML=`<div class="metric"><div class="lbl">Active orders</div><div class="val">${orders.filter(o=>o.status!=='Archived').length}</div></div><div class="metric"><div class="lbl">Total revenue</div><div class="val">${f0(tRev)}</div></div><div class="metric"><div class="lbl">Gross margin</div><div class="val">${fp(avgM)}</div></div><div class="metric"><div class="lbl">Customers</div><div class="val">${customers.length}</div></div><div class="metric"><div class="lbl">Collections</div><div class="val">${collections.length}</div></div>`;const rP=tRev>0?tRetail/tRev*100:0,wP=tRev>0?tWS/tRev*100:0,cP=tRev>0?tCust/tRev*100:0;document.getElementById('dchannel').innerHTML=`<div class="g3"><div class="metric"><div class="lbl">Retail</div><div class="val" style="color:#378ADD">${f0(tRetail)}</div><div class="sub">${fp(rP)} of total</div></div><div class="metric"><div class="lbl">Wholesale</div><div class="val" style="color:#639922">${f0(tWS)}</div><div class="sub">${fp(wP)} of total</div></div><div class="metric"><div class="lbl">Custom orders</div><div class="val" style="color:#BA7517">${f0(tCust)}</div><div class="sub">${fp(cP)} of total</div></div></div><div class="segment-bar"><div class="seg-retail" style="width:${rP}%"></div><div class="seg-ws" style="width:${wP}%"></div><div class="seg-custom" style="width:${cP}%"></div></div><div style="display:flex;gap:14px;font-size:11px;color:var(--color-text-secondary)"><span><span style="color:#378ADD">■</span> Retail</span><span><span style="color:#639922">■</span> Wholesale</span><span><span style="color:#BA7517">■</span> Custom</span></div>`;document.getElementById('dorders').innerHTML=orders.filter(o=>o.status!=='Archived').slice(0,5).map(o=>{const c=calcOrder(o);return`<div style="display:flex;justify-content:space-between;align-items:center;padding:7px 0;border-bottom:.5px solid var(--color-border-tertiary)"><div><div style="font-weight:500;font-size:13px">${o.id}${o.isActualized?` <span class="badge bok" style="font-size:10px">Act.</span>`:''}</div><div style="font-size:11px;color:var(--color-text-secondary)">${supName(o.supplier)} · ${c.units} units</div></div><div style="text-align:right"><span class="badge ${sbadge(o.status)}">${o.status}</span><div style="font-size:11px;color:var(--color-text-secondary);margin-top:2px">${f0(c.tLanded)}</div></div></div>`;}).join('');const sorted=[...customers].map(c=>({c,stats:calcCustomer(c)})).sort((a,b)=>b.stats.tRev-a.stats.tRev);document.getElementById('dtop-customers').innerHTML=sorted.slice(0,5).map(({c,stats})=>`<div style="display:flex;justify-content:space-between;align-items:center;padding:7px 0;border-bottom:.5px solid var(--color-border-tertiary);cursor:pointer" onclick="viewCustomer('${c.id}')"><div style="display:flex;align-items:center;gap:10px"><div class="avatar" style="width:32px;height:32px;font-size:12px;background:${custCol(c.id)}22;color:${custCol(c.id)}">${c.company.slice(0,2).toUpperCase()}</div><div><div style="font-weight:500;font-size:13px">${c.company}</div><div style="font-size:11px;color:var(--color-text-secondary)">${c.type} · ${stats.orderCount} order${stats.orderCount!==1?'s':''}</div></div></div><div style="text-align:right"><div style="font-weight:500;font-size:13px">${f0(stats.tRev)}</div><div style="font-size:11px;color:${stats.margin>50?'#639922':stats.margin>30?'#BA7517':'#E24B4A'}">${fp(stats.margin)} margin</div></div></div>`).join('');document.getElementById('dcolls').innerHTML=collections.map(c=>{const pl=getCollPL(c);return`<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:.5px solid var(--color-border-tertiary);flex-wrap:wrap;gap:8px"><div><span style="font-weight:500;font-size:13px;margin-right:8px">${c.name}</span><span class="badge bneutral">${c.season||''}</span></div><div style="display:flex;gap:14px;font-size:12px;flex-wrap:wrap"><span>${pl.orders} orders</span><span style="color:#378ADD">Retail: ${f0(pl.rRev)}</span><span style="color:#639922">WS: ${f0(pl.wRev)}</span><span style="font-weight:500;color:${pl.margin>50?'#639922':pl.margin>30?'#BA7517':'#E24B4A'}">Margin: ${fp(pl.margin)}</span><button class="btn btnsm" onclick="viewColl('${c.id}')">View →</button></div></div>`;}).join('');}

function showCatTab(id,el){['cat-types','cat-designs','cat-colors'].forEach(t=>{const e=document.getElementById(t);if(e)e.style.display='none';});document.querySelectorAll('#page-catalogue .tab').forEach(t=>t.classList.remove('active'));document.getElementById(id).style.display='block';el.classList.add('active');}
function renderCatalogue(){renderProdChips();renderGroupList();renderDesignList();renderColorList();}
function renderProdChips(){const groupOrder=[...productGroups.map(g=>g.id),''];const byGroup=(list)=>{const grouped={};list.forEach(p=>{const k=p.groupId||'';if(!grouped[k])grouped[k]=[];grouped[k].push(p);});let html='';groupOrder.forEach(gid=>{if(!grouped[gid])return;html+=`<div style="margin-bottom:10px"><div style="font-size:11px;color:var(--color-text-secondary);text-transform:uppercase;letter-spacing:.04em;margin-bottom:6px">${gid?grpName(gid):'No group'}</div><div>`;grouped[gid].forEach(p=>{html+=`<span class="chip edit-chip" onclick="openProdModal('','${p.id}')">${p.name}</span>`;});html+='</div></div>';});return html||'<div style="font-size:13px;color:var(--color-text-secondary)">None yet.</div>';};document.getElementById('core-chips').innerHTML=byGroup(coreProducts);document.getElementById('custom-chips').innerHTML=byGroup(customProducts);}
function renderGroupList(){document.getElementById('group-list').innerHTML=productGroups.map(g=>`<div style="display:flex;align-items:center;justify-content:space-between;padding:7px 0;border-bottom:.5px solid var(--color-border-tertiary)"><span style="font-size:13px">${g.name}</span><div style="display:flex;gap:8px;font-size:12px;color:var(--color-text-secondary)"><span>${allProducts().filter(p=>p.groupId===g.id).length} products</span><button class="btn btnsm" onclick="openGroupModal('${g.id}')">Edit</button></div></div>`).join('');}
function renderDesignList(){const cats=[...new Set(designs.map(d=>d.cat||'Uncategorised'))];let html='';cats.forEach(cat=>{const ds=designs.filter(d=>(d.cat||'Uncategorised')===cat);html+=`<div style="margin-bottom:14px"><div style="font-size:11px;color:var(--color-text-secondary);text-transform:uppercase;letter-spacing:.04em;margin-bottom:6px">${cat}</div><div>`;ds.forEach(d=>{html+=`<span class="chip edit-chip" onclick="openDesignModal('${d.id}')">${d.name}</span>`;});html+='</div></div>';});document.getElementById('design-list').innerHTML=html||'<div style="font-size:13px;color:var(--color-text-secondary)">No designs yet.</div>';}
function renderColorList(){document.getElementById('color-list').innerHTML='<div style="display:flex;flex-wrap:wrap;gap:6px">'+colors.map(c=>`<span class="chip edit-chip" onclick="openColorModal('${c.id}')">${c.name}</span>`).join('')+'</div>';}
function openProdModal(category,existingId){editProdId=existingId||null;editProdType=existingId?([...coreProducts].find(x=>x.id===existingId)?'core':'custom'):(category||'core');const p=existingId?allProducts().find(x=>x.id===existingId):null;document.getElementById('prod-modal-ttl').textContent=p?'Edit product':'Add product — '+(editProdType==='core'?'core':'custom');document.getElementById('prod-name').value=p?p.name:'';document.getElementById('prod-notes').value=p?p.notes||'':'';const gs=document.getElementById('prod-group');gs.innerHTML='<option value="">No group</option>'+productGroups.map(g=>`<option value="${g.id}" ${p&&p.groupId===g.id?'selected':''}>${g.name}</option>`).join('');document.getElementById('prod-del-btn').style.display=p?'inline-block':'none';document.getElementById('modal-prod').style.display='flex';}
function saveProd(){const name=document.getElementById('prod-name').value.trim();if(!name){alert('Product name required.');return;}const d={name,groupId:document.getElementById('prod-group').value||'',notes:document.getElementById('prod-notes').value};const list=editProdType==='core'?coreProducts:customProducts;if(editProdId){Object.assign(list.find(x=>x.id===editProdId),d);}else{list.push({id:(editProdType==='core'?'p':'cp')+Date.now(),...d});}closeM('modal-prod');renderCatalogue();}
function deleteProd(){if(!confirm('Delete this product?'))return;if(editProdType==='core'){const i=coreProducts.findIndex(x=>x.id===editProdId);if(i>-1)coreProducts.splice(i,1);}else{const i=customProducts.findIndex(x=>x.id===editProdId);if(i>-1)customProducts.splice(i,1);}closeM('modal-prod');renderCatalogue();}
function openGroupModal(id){editGroupId=id||null;const g=id?productGroups.find(x=>x.id===id):null;document.getElementById('group-modal-ttl').textContent=g?'Edit group':'Add group';document.getElementById('group-name').value=g?g.name:'';document.getElementById('group-del-btn').style.display=g?'inline-block':'none';document.getElementById('modal-group').style.display='flex';}
function saveGroup(){const name=document.getElementById('group-name').value.trim();if(!name){alert('Group name required.');return;}if(editGroupId){productGroups.find(x=>x.id===editGroupId).name=name;}else{productGroups.push({id:'g'+Date.now(),name});}closeM('modal-group');renderCatalogue();}
function deleteGroup(){if(!confirm('Delete group?'))return;const i=productGroups.findIndex(x=>x.id===editGroupId);if(i>-1){allProducts().forEach(p=>{if(p.groupId===editGroupId)p.groupId='';});productGroups.splice(i,1);}closeM('modal-group');renderCatalogue();}
function openDesignModal(id){editDesignId=id||null;const d=id?designs.find(x=>x.id===id):null;document.getElementById('design-modal-ttl').textContent=d?'Edit design':'Add design';document.getElementById('design-name').value=d?d.name:'';document.getElementById('design-cat').value=d?d.cat||'':'';document.getElementById('design-notes').value=d?d.notes||'':'';document.getElementById('design-del-btn').style.display=d?'inline-block':'none';document.getElementById('modal-design').style.display='flex';}
function saveDesign(){const name=document.getElementById('design-name').value.trim();if(!name){alert('Name required.');return;}const d={name,cat:document.getElementById('design-cat').value.trim(),notes:document.getElementById('design-notes').value};if(editDesignId){Object.assign(designs.find(x=>x.id===editDesignId),d);}else{designs.push({id:'d'+Date.now(),...d});}closeM('modal-design');renderCatalogue();}
function deleteDesign(){if(!confirm('Delete?'))return;const i=designs.findIndex(x=>x.id===editDesignId);if(i>-1)designs.splice(i,1);closeM('modal-design');renderCatalogue();}
function openColorModal(id){editColorId=id||null;const c=id?colors.find(x=>x.id===id):null;document.getElementById('color-modal-ttl').textContent=c?'Edit color':'Add color';document.getElementById('color-name').value=c?c.name:'';document.getElementById('color-del-btn').style.display=c?'inline-block':'none';document.getElementById('modal-color').style.display='flex';}
function saveColor(){const name=document.getElementById('color-name').value.trim();if(!name){alert('Name required.');return;}if(editColorId){colors.find(x=>x.id===editColorId).name=name;}else{colors.push({id:'cl'+Date.now(),name});}closeM('modal-color');renderCatalogue();}
function deleteColor(){if(!confirm('Delete?'))return;const i=colors.findIndex(x=>x.id===editColorId);if(i>-1)colors.splice(i,1);closeM('modal-color');renderCatalogue();}

function filterCusts(q,type){return customers.filter(c=>{const qm=!q||c.company.toLowerCase().includes(q.toLowerCase())||c.contact.toLowerCase().includes(q.toLowerCase());return qm&&(!type||c.type===type);});}
function renderCustomers(list){const all=list||customers;const allStats=customers.map(c=>calcCustomer(c));const totRev=allStats.reduce((a,s)=>a+s.tRev,0),totWS=allStats.reduce((a,s)=>a+s.wsRev,0),totCust=allStats.reduce((a,s)=>a+s.custRev,0),avgLTV=customers.length>0?totRev/customers.length:0;document.getElementById('cust-summary-metrics').innerHTML=`<div class="metric"><div class="lbl">Customers</div><div class="val">${customers.length}</div></div><div class="metric"><div class="lbl">WS + custom rev</div><div class="val">${f0(totRev)}</div></div><div class="metric"><div class="lbl">Wholesale rev</div><div class="val" style="color:#639922">${f0(totWS)}</div></div><div class="metric"><div class="lbl">Custom rev</div><div class="val" style="color:#BA7517">${f0(totCust)}</div></div><div class="metric"><div class="lbl">Avg LTV</div><div class="val">${f0(avgLTV)}</div></div>`;document.getElementById('cust-grid').innerHTML=all.map(c=>{const stats=calcCustomer(c),col=custCol(c.id),init=c.company.slice(0,2).toUpperCase();const wP=stats.tRev>0?stats.wsRev/stats.tRev*100:0,cP=stats.tRev>0?stats.custRev/stats.tRev*100:0;return`<div class="cust-card" onclick="viewCustomer('${c.id}')"><div style="display:flex;align-items:center;gap:12px;margin-bottom:12px"><div class="avatar" style="background:${col}22;color:${col}">${init}</div><div style="flex:1"><div style="font-weight:500;font-size:14px;display:flex;align-items:center;gap:8px">${c.company} ${tierBadge(stats.tRev)}</div><div style="font-size:12px;color:var(--color-text-secondary)">${c.type} · ${c.country||''}</div></div><button class="btn btnsm" onclick="event.stopPropagation();openCustModal('${c.id}')">Edit</button></div><div class="g3" style="margin-bottom:10px"><div class="metric"><div class="lbl">Total revenue</div><div class="val">${f0(stats.tRev)}</div></div><div class="metric"><div class="lbl">Orders</div><div class="val">${stats.orderCount}</div></div><div class="metric"><div class="lbl">Avg order</div><div class="val">${f0(stats.avgOrder)}</div></div></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px"><div class="metric"><div class="lbl">WS revenue</div><div class="val" style="color:#639922;font-size:16px">${f0(stats.wsRev)}</div></div><div class="metric"><div class="lbl">Custom revenue</div><div class="val" style="color:#BA7517;font-size:16px">${f0(stats.custRev)}</div></div></div><div class="segment-bar" style="height:6px"><div class="seg-ws" style="width:${wP}%"></div><div class="seg-custom" style="width:${cP}%"></div></div><div style="display:flex;justify-content:space-between;font-size:11px;color:var(--color-text-secondary);margin-top:4px"><span>${stats.productCount} products · ${stats.units} units</span><span style="color:${stats.margin>50?'#639922':stats.margin>30?'#BA7517':'#E24B4A'};font-weight:500">${fp(stats.margin)} margin</span></div></div>`;}).join('');}
function viewCustomer(id){const c=customers.find(x=>x.id===id);if(!c)return;const stats=calcCustomer(c),col=custCol(c.id),init=c.company.slice(0,2).toUpperCase();const ordersCalc=stats.ords.map(o=>({o,c:calcOrder(o)}));document.getElementById('cust-detail-content').innerHTML=`<div style="display:flex;align-items:flex-start;gap:16px;margin-bottom:1.5rem;flex-wrap:wrap"><div class="avatar" style="width:56px;height:56px;font-size:18px;background:${col}22;color:${col}">${init}</div><div style="flex:1"><div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:4px"><h2 style="font-size:18px;font-weight:500">${c.company}</h2>${tierBadge(stats.tRev)}<span class="badge ${c.type==='Wholesale'?'bwholesale':c.type==='Custom'?'bcustom':'binfo'}">${c.type}</span></div><div style="font-size:13px;color:var(--color-text-secondary);display:flex;gap:16px;flex-wrap:wrap">${c.contact?`<span>${c.contact}</span>`:''}${c.email?`<span style="color:var(--color-text-info)">${c.email}</span>`:''}${c.phone?`<span>${c.phone}</span>`:''}${c.country?`<span>${c.country}</span>`:''}</div></div><button class="btn btnsm" onclick="openCustModal('${c.id}')">Edit</button></div><div class="g5"><div class="metric"><div class="lbl">Lifetime value</div><div class="val">${f0(stats.tRev)}</div></div><div class="metric"><div class="lbl">Total orders</div><div class="val">${stats.orderCount}</div></div><div class="metric"><div class="lbl">Avg order value</div><div class="val">${f0(stats.avgOrder)}</div></div><div class="metric"><div class="lbl">Products bought</div><div class="val">${stats.productCount}</div></div><div class="metric"><div class="lbl">Gross margin</div><div class="val" style="color:${stats.margin>50?'#639922':stats.margin>30?'#BA7517':'#E24B4A'}">${fp(stats.margin)}</div></div></div><div class="card"><div class="ctitle">Purchase history</div><table><thead><tr><th>Order</th><th>Date</th><th>Collection</th><th>Status</th><th>WS rev</th><th>Custom rev</th><th>Total</th><th>Margin</th></tr></thead><tbody>${ordersCalc.map(({o,c})=>{const wR=c.wRev,cuR=c.cRev,tot=wR+cuR,lnd=tot>0?(wR+cuR)/c.tRev*c.tLanded:0,m=tot>0?(tot-lnd)/tot*100:0;return`<tr><td style="font-weight:500">${o.id}</td><td>${o.date}</td><td>${collName(o.collectionId)||'—'}</td><td><span class="badge ${sbadge(o.status)}">${o.status}</span></td><td style="color:#639922">${f0(wR)}</td><td style="color:#BA7517">${f0(cuR)}</td><td style="font-weight:500">${f0(tot)}</td><td style="color:${m>50?'#639922':m>30?'#BA7517':'#E24B4A'}">${fp(m)}</td></tr>`;}).join('')}</tbody></table></div>`;document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));document.getElementById('page-cust-detail').classList.add('active');}
function openCustModal(editId){editCustId=editId||null;const c=editId?customers.find(x=>x.id===editId):null;document.getElementById('cust-modal-ttl').textContent=c?'Edit customer':'Add customer';['company','contact','email','phone','country','addr','terms','notes'].forEach(f=>{const el=document.getElementById('cust-'+f);if(el)el.value=c?c[f==='addr'?'address':f]||'':'';});document.getElementById('cust-type').value=c?c.type:'Wholesale';document.getElementById('cust-disc').value=c?c.discount||0:0;document.getElementById('cust-ord-picks').innerHTML=orders.map(o=>`<label class="order-check"><input type="checkbox" value="${o.id}" ${c&&c.orderIds.includes(o.id)?'checked':''}><div style="flex:1"><div style="font-weight:500;font-size:13px">${o.id} — ${supName(o.supplier)}</div><div style="font-size:11px;color:var(--color-text-secondary)">${o.items.map(i=>i.name).join(', ')}</div></div><span class="badge ${sbadge(o.status)}">${o.status}</span></label>`).join('');document.getElementById('cust-coll-picks').innerHTML=collections.map(cl=>`<label class="order-check"><input type="checkbox" value="${cl.id}" ${c&&c.collectionIds.includes(cl.id)?'checked':''}><div><div style="font-weight:500;font-size:13px">${cl.name}</div><div style="font-size:11px;color:var(--color-text-secondary)">${cl.season||''}</div></div></label>`).join('');document.getElementById('modal-cust').style.display='flex';}
function saveCust(){const company=document.getElementById('cust-company').value.trim();if(!company){alert('Name required.');return;}const orderIds=[...document.querySelectorAll('#cust-ord-picks input:checked')].map(i=>i.value);const collectionIds=[...document.querySelectorAll('#cust-coll-picks input:checked')].map(i=>i.value);const d={company,contact:document.getElementById('cust-contact').value,email:document.getElementById('cust-email').value,phone:document.getElementById('cust-phone').value,type:document.getElementById('cust-type').value,country:document.getElementById('cust-country').value,discount:parseFloat(document.getElementById('cust-disc').value)||0,address:document.getElementById('cust-addr').value,terms:document.getElementById('cust-terms').value,notes:document.getElementById('cust-notes').value,orderIds,collectionIds};if(editCustId){Object.assign(customers.find(x=>x.id===editCustId),d);}else{customers.push({id:'c'+Date.now(),...d});}closeM('modal-cust');renderCustomers();}

function renderCollections(){document.getElementById('coll-cnt').textContent=`${collections.length} collection${collections.length!==1?'s':''}`;document.getElementById('colls-list').innerHTML=collections.map(c=>{const pl=getCollPL(c);return`<div class="card"><div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;margin-bottom:12px"><div><div style="font-size:16px;font-weight:500;margin-bottom:4px">${c.name} <span class="badge bneutral">${c.season||''}</span></div><div style="font-size:12px;color:var(--color-text-secondary)">${c.desc}</div></div><div style="display:flex;gap:8px"><button class="btn btnsm" onclick="viewColl('${c.id}')">View P&L</button><button class="btn btnsm" onclick="openCollModal('${c.id}')">Edit</button></div></div><div class="g5"><div class="metric"><div class="lbl">Orders</div><div class="val">${pl.orders}</div></div><div class="metric"><div class="lbl">Units</div><div class="val">${pl.units}</div></div><div class="metric"><div class="lbl">Retail rev</div><div class="val" style="color:#378ADD">${f0(pl.rRev)}</div></div><div class="metric"><div class="lbl">WS rev</div><div class="val" style="color:#639922">${f0(pl.wRev)}</div></div><div class="metric"><div class="lbl">Margin</div><div class="val" style="color:${pl.margin>50?'#639922':pl.margin>30?'#BA7517':'#E24B4A'}">${fp(pl.margin)}</div></div></div></div>`;}).join('');}
function viewColl(id){const c=collections.find(x=>x.id===id);if(!c)return;const pl=getCollPL(c);pl.ords.forEach(o=>calcOrder(o));const rP=pl.tRev>0?pl.rRev/pl.tRev*100:0,wP=pl.tRev>0?pl.wRev/pl.tRev*100:0,cP=pl.tRev>0?pl.cRev/pl.tRev*100:0;document.getElementById('coll-detail').innerHTML=`<div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;margin-bottom:1rem"><div><h2 style="font-size:18px;font-weight:500">${c.name}</h2><div style="font-size:13px;color:var(--color-text-secondary);margin-top:4px">${c.season||''} ${c.desc?'· '+c.desc:''}</div></div></div><div class="g5"><div class="metric"><div class="lbl">Orders</div><div class="val">${pl.orders}</div></div><div class="metric"><div class="lbl">Units</div><div class="val">${pl.units}</div></div><div class="metric"><div class="lbl">Landed cost</div><div class="val">${f0(pl.tLanded)}</div></div><div class="metric"><div class="lbl">Total revenue</div><div class="val">${f0(pl.tRev)}</div></div><div class="metric"><div class="lbl">Gross margin</div><div class="val" style="color:${pl.margin>50?'#639922':pl.margin>30?'#BA7517':'#E24B4A'}">${fp(pl.margin)}</div></div></div><div class="card"><div class="ctitle">P&L summary</div><div style="background:var(--color-background-secondary);border-radius:var(--border-radius-md);padding:10px 14px"><div class="pl-row"><span>Total landed cost</span><span>${f0(pl.tLanded)}</span></div><div class="pl-row"><span style="color:#378ADD">Retail revenue</span><span>${f0(pl.rRev)}</span></div><div class="pl-row"><span style="color:#639922">Wholesale revenue</span><span>${f0(pl.wRev)}</span></div><div class="pl-row"><span style="color:#BA7517">Custom revenue</span><span>${f0(pl.cRev)}</span></div><div class="pl-row" style="font-weight:500"><span>Gross revenue</span><span>${f0(pl.tRev)}</span></div><div class="pl-row" style="font-weight:500"><span>Gross profit</span><span>${f0(pl.tRev-pl.tLanded)}</span></div><div class="pl-row" style="font-weight:500"><span>Gross margin</span><span style="color:${pl.margin>50?'#639922':pl.margin>30?'#BA7517':'#E24B4A'}">${fp(pl.margin)}</span></div></div></div>`;document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));document.getElementById('page-coll-detail').classList.add('active');}
function openCollModal(editId){editCollId=editId||null;const c=editId?collections.find(x=>x.id===editId):null;document.getElementById('coll-modal-ttl').textContent=c?'Edit collection':'New collection';document.getElementById('coll-name').value=c?c.name:'';document.getElementById('coll-season').value=c?c.season||'':'';document.getElementById('coll-desc').value=c?c.desc||'':'';document.getElementById('coll-ord-picks').innerHTML=orders.map(o=>`<label class="order-check"><input type="checkbox" value="${o.id}" ${c&&c.orderIds.includes(o.id)?'checked':''}><div style="flex:1"><div style="font-weight:500;font-size:13px">${o.id} — ${supName(o.supplier)}</div><div style="font-size:11px;color:var(--color-text-secondary)">${o.items.map(i=>i.name).join(', ')}</div></div><span class="badge ${sbadge(o.status)}">${o.status}</span></label>`).join('');document.getElementById('modal-coll').style.display='flex';}
function saveColl(){const name=document.getElementById('coll-name').value.trim();if(!name){alert('Name required.');return;}const ids=[...document.querySelectorAll('#coll-ord-picks input:checked')].map(i=>i.value);if(editCollId){const c=collections.find(x=>x.id===editCollId);c.name=name;c.season=document.getElementById('coll-season').value;c.desc=document.getElementById('coll-desc').value;c.orderIds=ids;}else{collections.push({id:'col'+Date.now(),name,season:document.getElementById('coll-season').value,desc:document.getElementById('coll-desc').value,orderIds:ids});}closeM('modal-coll');renderCollections();}

function filtOrds(q,sup,stat){return orders.filter(o=>{const qm=!q||o.id.toLowerCase().includes(q.toLowerCase())||supName(o.supplier).toLowerCase().includes(q.toLowerCase());return qm&&(!sup||o.supplier===sup)&&(!stat||o.status===stat);});}
function renderOrders(list){const sf=document.getElementById('o-sf');if(sf.children.length<2)suppliers.forEach(s=>{const o=document.createElement('option');o.value=s.id;o.textContent=s.name;sf.appendChild(o);});document.getElementById('ord-tbody').innerHTML=(list||orders).map(o=>{const c=calcOrder(o);return`<tr><td style="font-weight:500">${o.id}${o.isActualized?` <span class="badge bok" style="font-size:10px">Act.</span>`:!o.isActualized&&o.status==='Delivered'?` <span class="badge bwarn" style="font-size:10px">Needs actuals</span>`:''}</td><td>${supName(o.supplier)}</td><td style="font-size:11px;color:var(--color-text-secondary)">${collName(o.collectionId)||'—'}</td><td><span class="badge ${sbadge(o.status)}">${o.status}</span></td><td>${c.units}</td><td>${f0(c.tLanded)}</td><td style="color:#378ADD">${f0(c.rRev)}</td><td style="color:#639922">${f0(c.wRev)}</td><td style="color:#BA7517">${f0(c.cRev)}</td><td style="color:${c.margin>50?'#639922':c.margin>30?'#BA7517':'#E24B4A'}">${fp(c.margin)}</td><td><button class="btn btnsm" onclick="openOrdDetail('${o.id}')">View</button></td></tr>`;}).join('');}
function openOrdDetail(id){const o=orders.find(x=>x.id===id);if(!o)return;const c=calcOrder(o);document.getElementById('modal-ord-content').innerHTML=`<div style="font-size:15px;font-weight:500;margin-bottom:1rem">${o.id} — ${supName(o.supplier)}</div>${!o.isActualized?`<div class="actual-flag">⚠ Using estimated costs.</div>`:''}<div class="g4" style="margin-bottom:1rem"><div class="metric"><div class="lbl">Units</div><div class="val">${c.units}</div></div><div class="metric"><div class="lbl">Landed</div><div class="val">${f0(c.tLanded)}</div></div><div class="metric"><div class="lbl">Revenue</div><div class="val">${f0(c.tRev)}</div></div><div class="metric"><div class="lbl">Margin</div><div class="val" style="color:${c.margin>50?'#639922':c.margin>30?'#BA7517':'#E24B4A'}">${fp(c.margin)}</div></div></div><div class="tabs"><div class="tab active" onclick="showOTab('odet',this)">Details</div><div class="tab" onclick="showOTab('oact',this)">Enter actuals</div><div class="tab" onclick="showOTab('otrk',this)">Tracking</div></div><div id="odet">${o.items.map(it=>`<div class="channel-block"><div style="font-weight:500;margin-bottom:4px">${it.name}</div><div style="font-size:12px;color:var(--color-text-secondary);margin-bottom:6px">Unit price: ${f2(it.unitPrice)} · Markup: ${it.markup}% · Retail: ${f2(it._retail||0)}</div><div style="display:flex;gap:8px;flex-wrap:wrap">${it.channels.map(ch=>`<span class="badge ${ch.type==='retail'?'bretail':ch.type==='wholesale'?'bwholesale':'bcustom'}">${ch.type==='retail'?'Retail':ch.type==='wholesale'?'WS':'Custom'}: ${ch.qty} × ${f2(ch.price)}</span>`).join('')}</div></div>`).join('')}<div style="display:flex;justify-content:flex-end;margin-top:1rem"><button class="btn btnsm btnp" onclick="driveSaveOrder&&driveSaveOrder('${o.id}')">Save to Drive</button></div></div><div id="oact" style="display:none"><div class="row" style="margin-bottom:10px"><div><label>Actual shipping ($)</label><input type="number" id="act-ship" value="${o.actShip??o.estShip}" min="0"></div><div><label>Actual clearing ($)</label><input type="number" id="act-clear" value="${o.actClear??o.estClear}" min="0"></div></div><div id="act-extras">${(o.actExtra.length?o.actExtra:o.estExtra).map((e,i)=>`<div class="extra-cost-row"><input value="${e.label}" placeholder="Label" style="flex:2" id="aelbl${i}"><input type="number" value="${e.amt}" min="0" style="flex:1" id="aeamt${i}"><button class="btn btnsm" onclick="this.closest('.extra-cost-row').remove()">×</button></div>`).join('')}</div><button class="btn btnsm" style="margin-bottom:1rem" onclick="addActX()">+ Add extra cost</button>${o.items.map((it,ii)=>`<div style="margin-bottom:10px"><div style="font-size:13px;font-weight:500;margin-bottom:6px">${it.name}</div><div class="szlabels">${SIZES.map(s=>`<span>${s}</span>`).join('')}</div><div class="szgrid">${SIZES.map((_,si)=>`<input type="number" value="${it.sizes[si]||0}" min="0" id="asz${ii}_${si}">`).join('')}</div><div style="display:flex;gap:10px;margin-top:6px;font-size:12px;align-items:center"><span>Adj (+/-):</span><input type="number" value="${it.adj||0}" style="width:70px" id="aadj${ii}"></div></div>`).join('')}<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:1rem"><button class="btn" onclick="closeM('modal-ord')">Cancel</button><button class="btn btnp" onclick="saveActuals('${o.id}')">Save actuals</button></div></div><div id="otrk" style="display:none"><div class="row" style="margin-bottom:10px"><div><label>Tracking #</label><input id="trk-num" value="${o.tracking||''}"></div><div><label>Carrier</label><select id="trk-carrier"><option value="">Select</option><option ${o.carrier==='FedEx'?'selected':''}>FedEx</option><option ${o.carrier==='DHL'?'selected':''}>DHL</option><option ${o.carrier==='UPS'?'selected':''}>UPS</option></select></div><div><label>Status</label><select id="trk-status">${['Active','Shipped','In transit','Delivered','Archived'].map(s=>`<option ${o.status===s?'selected':''}>${s}</option>`).join('')}</select></div></div><div><label>Est. delivery</label><input id="trk-eta" value="${o.eta||''}" style="max-width:200px"></div><div class="divider"></div>${o.steps.map((s,i)=>`<label style="display:flex;align-items:center;gap:10px;padding:6px 0;cursor:pointer"><input type="checkbox" id="ts${i}" ${s.d?'checked':''} style="width:auto"><span style="font-size:13px">${s.l}</span></label>`).join('')}<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:1rem"><button class="btn" onclick="closeM('modal-ord')">Close</button><button class="btn btnp" onclick="saveTrk('${o.id}')">Save</button></div></div>`;document.getElementById('modal-ord').style.display='flex';}
function showOTab(id,el){['odet','oact','otrk'].forEach(t=>{const e=document.getElementById(t);if(e)e.style.display='none';});document.querySelectorAll('#modal-ord-content .tab').forEach(t=>t.classList.remove('active'));document.getElementById(id).style.display='block';el.classList.add('active');}
function addActX(){const wrap=document.getElementById('act-extras'),i=wrap.children.length;const div=document.createElement('div');div.className='extra-cost-row';div.innerHTML=`<input placeholder="Label" style="flex:2" id="aelbl${i}"><input type="number" value="0" min="0" style="flex:1" id="aeamt${i}"><button class="btn btnsm" onclick="this.closest('.extra-cost-row').remove()">×</button>`;wrap.appendChild(div);}
function saveActuals(ordId){const o=orders.find(x=>x.id===ordId);if(!o)return;o.actShip=parseFloat(document.getElementById('act-ship').value)||0;o.actClear=parseFloat(document.getElementById('act-clear').value)||0;o.actExtra=[];document.querySelectorAll('#act-extras .extra-cost-row').forEach(row=>{const inputs=row.querySelectorAll('input');const lbl=inputs[0],amt=inputs[1];if(lbl&&amt&&lbl.value.trim())o.actExtra.push({label:lbl.value.trim(),amt:parseFloat(amt.value)||0});});o.items.forEach((it,ii)=>{it.sizes=SIZES.map((_,si)=>{const el=document.getElementById(`asz${ii}_${si}`);return el?parseInt(el.value)||0:it.sizes[si];});const adjEl=document.getElementById(`aadj${ii}`);if(adjEl)it.adj=parseInt(adjEl.value)||0;});o.isActualized=true;closeM('modal-ord');renderDashboard();renderOrders(orders);}
function saveTrk(ordId){const o=orders.find(x=>x.id===ordId);if(!o)return;o.tracking=document.getElementById('trk-num').value;o.carrier=document.getElementById('trk-carrier').value;o.status=document.getElementById('trk-status').value;o.eta=document.getElementById('trk-eta').value;o.steps.forEach((s,i)=>{const el=document.getElementById('ts'+i);if(el)s.d=el.checked;});closeM('modal-ord');renderDashboard();}

function renderSuppliers(){
  document.getElementById('sup-cnt').textContent=`${suppliers.length} supplier${suppliers.length!==1?'s':''}`;
  document.getElementById('sup-grid').innerHTML=suppliers.map(s=>{
    const init=s.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase(),col=supCol(s.id),oc=orders.filter(o=>o.supplier===s.id).length;
    const prods=getSupplierProducts(s.id);
    return`<div class="card"><div style="display:flex;align-items:center;gap:12px;margin-bottom:12px"><div class="avatar" style="background:${col}22;color:${col}">${init}</div><div><div style="font-weight:500;font-size:14px">${s.name}</div><div style="font-size:12px;color:var(--color-text-secondary)">${s.country||''} · ${s.currency}</div></div><button class="btn btnsm" style="margin-left:auto" onclick="openSupModal('${s.id}')">Edit</button></div>
    <div class="divider"></div>
    <div style="display:flex;flex-direction:column;gap:5px;font-size:12px;margin-bottom:10px">${s.contact?`<div style="display:flex;gap:8px"><span style="color:var(--color-text-secondary);min-width:75px">Contact</span><span>${s.contact}</span></div>`:''}${s.email?`<div style="display:flex;gap:8px"><span style="color:var(--color-text-secondary);min-width:75px">Email</span><span style="color:var(--color-text-info)">${s.email}</span></div>`:''}${s.terms?`<div style="display:flex;gap:8px"><span style="color:var(--color-text-secondary);min-width:75px">Terms</span><span>${s.terms}</span></div>`:''}${s.lead?`<div style="display:flex;gap:8px"><span style="color:var(--color-text-secondary);min-width:75px">Lead time</span><span>${s.lead}</span></div>`:''}</div>
    <div class="divider"></div>
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px"><span style="font-size:11px;color:var(--color-text-secondary);text-transform:uppercase;letter-spacing:.04em">Products (${prods.length})</span><button class="btn btnsm" onclick="openSupModal('${s.id}','products')" style="font-size:11px">Manage</button></div>
    ${prods.length?`<div style="display:flex;flex-direction:column;gap:3px">${prods.slice(0,4).map(sp=>{const p=allProducts().find(x=>x.id===sp.productId);return p?`<div style="display:flex;justify-content:space-between;font-size:12px;padding:3px 0"><span>${p.name}</span><span style="color:var(--color-text-secondary);font-family:var(--font-mono)">${f2(sp.cost)}</span></div>`:'';}).join('')}${prods.length>4?`<div style="font-size:11px;color:var(--color-text-secondary);margin-top:2px">+${prods.length-4} more</div>`:''}</div>`:`<div style="font-size:12px;color:var(--color-text-secondary);font-style:italic">No products assigned yet</div>`}
    <div class="divider"></div><div style="font-size:12px;color:var(--color-text-secondary)">${oc} order${oc!==1?'s':''}</div></div>`;
  }).join('');
}

function openSupModal(editId,openTab){
  editSupId=editId||null;const s=editId?suppliers.find(x=>x.id===editId):null;
  document.getElementById('sup-modal-ttl').textContent=s?'Edit supplier':'Add supplier';
  ['name','contact','email','phone','country','addr','terms','lead','notes'].forEach(f=>{const el=document.getElementById('sup-'+f);if(el)el.value=s?s[f==='addr'?'address':f]||'':'';});
  document.getElementById('sup-cur').value=s?s.currency:'USD';
  _supProdDraft=editId?(supplierProducts[editId]||[]).map(x=>({...x})):[];
  renderSupProdList();
  const isProducts=openTab==='products';
  showSupTab(isProducts?'sup-tab-products':'sup-tab-info',document.querySelector(isProducts?'#sup-modal-tabs .tab:nth-child(2)':'#sup-modal-tabs .tab:first-child'));
  document.getElementById('modal-sup').style.display='flex';
}

function saveSup(){
  const name=document.getElementById('sup-name').value.trim();if(!name){alert('Name required.');return;}
  document.querySelectorAll('#sup-prod-list input[data-pid]').forEach(inp=>{const sp=_supProdDraft.find(x=>x.productId===inp.dataset.pid);if(sp)sp.cost=parseFloat(inp.value)||0;});
  const d={name,contact:document.getElementById('sup-contact').value,email:document.getElementById('sup-email').value,phone:document.getElementById('sup-phone').value,country:document.getElementById('sup-country').value,currency:document.getElementById('sup-cur').value,address:document.getElementById('sup-addr').value,terms:document.getElementById('sup-terms').value,lead:document.getElementById('sup-lead').value,notes:document.getElementById('sup-notes').value};
  if(editSupId){Object.assign(suppliers.find(x=>x.id===editSupId),d);supplierProducts[editSupId]=[..._supProdDraft];}
  else{const newId='s'+Date.now();suppliers.push({id:newId,...d});supplierProducts[newId]=[..._supProdDraft];editSupId=newId;}
  closeM('modal-sup');renderSuppliers();populateDropdowns();
}

function showStab(id,el){['st-carriers','st-drive','st-markup'].forEach(t=>{const e=document.getElementById(t);if(e)e.style.display='none';});document.querySelectorAll('#page-settings .tab').forEach(t=>t.classList.remove('active'));document.getElementById(id).style.display='block';el.classList.add('active');}
function addMarkup(){const v=parseInt(document.getElementById('new-mu').value);if(isNaN(v))return;if(!markups.includes(v)){markups.push(v);markups.sort((a,b)=>a-b);}document.getElementById('new-mu').value='';renderChips();}
function renderChips(){document.getElementById('markup-chips').innerHTML=markups.map(m=>`<span style="background:var(--color-background-secondary);border:.5px solid var(--color-border-tertiary);border-radius:var(--border-radius-md);padding:4px 10px;font-size:12px;display:inline-flex;align-items:center;gap:6px">${m}% <span onclick="markups=markups.filter(x=>x!==${m});renderChips()" style="cursor:pointer;color:var(--color-text-secondary);font-size:14px;line-height:1">×</span></span>`).join('');}

function closeM(id){document.getElementById(id).style.display='none';}
function populateDropdowns(){const ss=document.getElementById('no-sup');ss.innerHTML='<option value="">Select supplier first...</option>'+suppliers.map(s=>`<option value="${s.id}">${s.name}</option>`).join('');const cs=document.getElementById('no-coll');cs.innerHTML='<option value="">None</option>'+collections.map(c=>`<option value="${c.id}">${c.name}</option>`).join('');}

function gotoPage(id){
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.nav button').forEach(b=>b.classList.remove('active'));
  document.getElementById('page-'+id).classList.add('active');
  document.querySelectorAll('.nav button').forEach(b=>{if(b.getAttribute('onclick')===`gotoPage('${id}')`)b.classList.add('active');});
  if(id==='new-order'){if(itemIdx===0)addItem();populateDropdowns();}
  if(id==='orders')renderOrders(orders);
  if(id==='suppliers-page')renderSuppliers();
  if(id==='collections')renderCollections();
  if(id==='customers')renderCustomers();
  if(id==='dashboard')renderDashboard();
  if(id==='catalogue')renderCatalogue();
  if(id==='settings')restoreDriveSettings();
}

renderDashboard();renderChips();
document.getElementById('no-date').value=new Date().toISOString().slice(0,10);
